import os
import httpx
import jwt  # PyJWT
from functools import lru_cache
from mcp.server.fastmcp import FastMCP

mcp = FastMCP("secure-server")

AUTH_SERVER = os.environ["AUTH_SERVER"]  # e.g. https://auth.example.com
REQUIRED_SCOPES = {"mcp:read"}

@lru_cache(maxsize=1)
def get_jwks():
    """Fetch JWK Set from the authorization server (cached)."""
    r = httpx.get(f"{AUTH_SERVER}/.well-known/jwks.json")
    r.raise_for_status()
    return jwt.PyJWKClient(f"{AUTH_SERVER}/.well-known/jwks.json")

def verify_token(token: str) -> dict:
    """Verify and decode a JWT access token."""
    jwks_client = get_jwks()
    signing_key = jwks_client.get_signing_key_from_jwt(token)
    payload = jwt.decode(
        token,
        signing_key.key,
        algorithms=["RS256", "ES256"],
        audience="https://mcp.example.com",  # must match aud claim
        issuer=AUTH_SERVER,
    )
    # Check scopes
    token_scopes = set(payload.get("scope", "").split())
    if not REQUIRED_SCOPES.issubset(token_scopes):
        raise jwt.InvalidTokenError("Insufficient scopes")
    return payload

# Middleware: extract and validate token before every request
from starlette.middleware.base import BaseHTTPMiddleware
from starlette.responses import JSONResponse

class BearerAuthMiddleware(BaseHTTPMiddleware):
    async def dispatch(self, request, call_next):
        # Allow discovery endpoints without auth
        if request.url.path in ("/.well-known/oauth-authorization-server",):
            return await call_next(request)

        auth_header = request.headers.get("Authorization", "")
        if not auth_header.startswith("Bearer "):
            return JSONResponse({"error": "unauthorized"}, status_code=401,
                                headers={"WWW-Authenticate": "Bearer"})
        token = auth_header[len("Bearer "):]
        try:
            payload = verify_token(token)
            request.state.token_payload = payload
        except jwt.PyJWTError as e:
            return JSONResponse({"error": "invalid_token", "detail": str(e)}, status_code=401,
                                headers={"WWW-Authenticate": 'Bearer error="invalid_token"'})
        return await call_next(request)

# Example: minimal authorization server using Authlib + FastAPI
# Install: pip install authlib fastapi uvicorn

from fastapi import FastAPI, Request, Form
from authlib.integrations.starlette_client import StarletteOAuth2
from authlib.jose import jwt as jose_jwt
import os, time, secrets

app = FastAPI()

# In-memory stores (use a real database in production)
clients: dict[str, dict] = {}
codes: dict[str, dict] = {}
tokens: dict[str, dict] = {}

@app.post("/register")
async def register(request: Request):
    body = await request.json()
    client_id = secrets.token_urlsafe(16)
    clients[client_id] = {**body, "client_id": client_id}
    return {"client_id": client_id}

@app.get("/authorize")
async def authorize(
    response_type: str, client_id: str, redirect_uri: str,
    scope: str, state: str, code_challenge: str, code_challenge_method: str
):
    # In a real server: show a login page. Here we auto-approve for demo.
    code = secrets.token_urlsafe(16)
    codes[code] = {
        "client_id": client_id,
        "redirect_uri": redirect_uri,
        "scope": scope,
        "code_challenge": code_challenge,
        "code_challenge_method": code_challenge_method,
    }
    from fastapi.responses import RedirectResponse
    return RedirectResponse(f"{redirect_uri}?code={code}&state={state}")

@app.post("/token")
async def token(
    grant_type: str = Form(...),
    code: str = Form(None),
    code_verifier: str = Form(None),
    client_id: str = Form(...),
    redirect_uri: str = Form(None),
    refresh_token: str = Form(None),
):
    import hashlib, base64
    if grant_type == "authorization_code":
        stored = codes.pop(code, None)
        if not stored or stored["client_id"] != client_id:
            return {"error": "invalid_grant"}
        # Verify PKCE
        verifier_hash = base64.urlsafe_b64encode(
            hashlib.sha256(code_verifier.encode()).digest()
        ).rstrip(b"=").decode()
        if verifier_hash != stored["code_challenge"]:
            return {"error": "invalid_grant", "detail": "PKCE verification failed"}
        access_token = secrets.token_urlsafe(32)
        refresh_tok = secrets.token_urlsafe(32)
        tokens[access_token] = {"client_id": client_id, "scope": stored["scope"]}
        return {
            "access_token": access_token,
            "token_type": "bearer",
            "expires_in": 3600,
            "refresh_token": refresh_tok,
            "scope": stored["scope"],
        }
    return {"error": "unsupported_grant_type"}
